(1, 1022, 'App\\Models\\Article', 1, NULL, 'Dolor recusandae quo quis hic iure est. Facere ut beatae vitae et atque animi. Nemo dolorem voluptatum numquam provident dolor velit.', 1, '2026-02-27 21:45:31', '2026-02-27 21:45:31'),
(2, 1023, 'App\\Models\\Article', 2, NULL, 'Et sequi sint nostrum. Voluptas eligendi labore consequuntur dignissimos error qui iusto nulla. Cumque laboriosam dolorum illo architecto eos. Qui qui qui hic et voluptas. Aut non voluptas tempore doloremque temporibus quidem alias.', 2, '2026-02-27 21:45:31', '2026-02-27 21:45:31'),
(3, 1024, 'App\\Models\\Article', 2, NULL, 'Possimus ea ducimus exercitationem et qui nulla. Magni est sint consequuntur. Numquam nostrum doloribus quibusdam. Nihil hic incidunt ea harum modi aliquam. Velit quasi deleniti repellendus est magnam distinctio dolor et.', 1, '2026-02-27 21:45:31', '2026-02-27 21:45:31'),
(4, 1025, 'App\\Models\\Article', 2, NULL, 'Ut rem sed est voluptatem sint in. Consectetur magnam at ipsa ducimus expedita non soluta. Quis itaque enim aut nam delectus tempore iure. Molestias eligendi explicabo et recusandae ipsum.', 0, '2026-02-27 21:45:32', '2026-02-27 21:45:32'),
(5, 1026, 'App\\Models\\Article', 2, NULL, 'Ducimus qui eum ullam aliquam. Eligendi quidem in asperiores vero vel animi dolorum. Amet exercitationem illum vel id sapiente voluptatem itaque. Qui sint esse eligendi omnis debitis.', 1, '2026-02-27 21:45:32', '2026-02-27 21:45:32'),
(6, 1027, 'App\\Models\\Article', 3, NULL, 'Molestiae minima labore qui temporibus mollitia consequatur. In alias laudantium cumque ea. Rem ex quisquam distinctio nisi soluta.', 0, '2026-02-27 21:45:32', '2026-02-27 21:45:32'),
(7, 1028, 'App\\Models\\Article', 3, NULL, 'Cum nisi nostrum enim occaecati delectus quis et. Architecto saepe veritatis et facilis mollitia et impedit dignissimos. Deserunt sed eveniet rerum impedit eius dolores suscipit. Quibusdam nemo cum quibusdam est est omnis. Fugiat debitis asperiores nemo.', 1, '2026-02-27 21:45:32', '2026-02-27 21:45:32'),
(8, 1029, 'App\\Models\\Article', 3, NULL, 'Magnam et omnis cupiditate illo quo voluptatem ducimus. Mollitia accusamus maxime voluptatibus sint. Odit est dignissimos accusamus. Tempora occaecati cum libero.', 0, '2026-02-27 21:45:32', '2026-02-27 21:45:32'),
(9, 1030, 'App\\Models\\Article', 3, NULL, 'Quidem ut fugit voluptatem est animi consequuntur. Qui ut in quisquam id fugit porro quasi. Qui similique est nihil quidem unde eveniet est. Quam soluta vero reiciendis laudantium illo vero.', 0, '2026-02-27 21:45:32', '2026-02-27 21:45:32'),
(10, 1031, 'App\\Models\\Article', 3, NULL, 'Totam et et neque vel maiores. Delectus expedita ea voluptatem cum voluptas. Voluptatum qui ullam non vero. Ab autem aperiam odio provident incidunt officia ea.', 0, '2026-02-27 21:45:32', '2026-02-27 21:45:32'),
(11, 1032, 'App\\Models\\Article', 3, NULL, 'Numquam omnis sint non nesciunt minima perferendis vel. At sapiente tempora quam. Natus voluptatem impedit atque sunt accusantium omnis sed. Repudiandae in modi ducimus et quis ut molestiae.', 0, '2026-02-27 21:45:32', '2026-02-27 21:45:32'),
